import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const ManagePackagesPage = () => {

  const [packages, setPackages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    name: '',
    destination: '',
    duration: '',
    price: '',
    availableSlots: '',
    description: ''
  });

  const load = async () => {
    try {
      setLoading(true);

      const res = await api.get('/packages');

      console.log("Packages:", res.data);

      setPackages(res.data.data);

    } catch (err) {
      console.error(err);
      setError('Failed to load packages.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const addPackage = async (e) => {
    e.preventDefault();

    try {

      const res = await api.post('/packages', formData);

      console.log("Created:", res.data);

      alert("Package added successfully");

      setFormData({
        name: '',
        destination: '',
        duration: '',
        price: '',
        availableSlots: '',
        description: ''
      });

      load();

    } catch (err) {

      console.error("Create error:", err.response?.data || err);

      alert("Failed to add package");

    }
  };

  return (
    <>
      <Navbar />

      <div className={styles.page}>

        <h1>✈️ Manage Packages</h1>

        <h2>Add New Package</h2>

        <form onSubmit={addPackage} className={styles.form}>

          <input
            type="text"
            name="name"
            placeholder="Package Name"
            value={formData.name}
            onChange={handleChange}
            required
          />

          <input
            type="text"
            name="destination"
            placeholder="Destination ID"
            value={formData.destination}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="duration"
            placeholder="Duration (days)"
            value={formData.duration}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="price"
            placeholder="Price"
            value={formData.price}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="availableSlots"
            placeholder="Available Slots"
            value={formData.availableSlots}
            onChange={handleChange}
            required
          />

          <textarea
            name="description"
            placeholder="Description"
            value={formData.description}
            onChange={handleChange}
          />

          <button type="submit" className={styles.btn}>
            Add Package
          </button>

        </form>

        {loading && <p>Loading…</p>}
        {error && <p style={{ color: "red" }}>{error}</p>}

        {!loading && !error && (

          <table className={styles.table}>

            <thead>
              <tr>
                <th>Name</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
              </tr>
            </thead>

            <tbody>

              {packages.length === 0 ? (
                <tr>
                  <td colSpan={4}>No packages found.</td>
                </tr>
              ) : packages.map((p) => (

                <tr key={p._id}>

                  <td>{p.name}</td>
                  <td>{p.destination?.name || '—'}</td>
                  <td>{p.duration} days</td>
                  <td>${p.price}</td>

                </tr>

              ))}

            </tbody>

          </table>

        )}

      </div>

    </>
  );
};

export default ManagePackagesPage;
